<template>
    <section>
        <div class="my-popups">
            <loader :is-visible="isLoading"></loader>

            <div class="modal d-block" v-if="isEditLimit">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div
                            class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                            <h5 class="modal-title">
                                {{ refCode === 'Update' ? $t('updatelimit') : $t('AddLimit') }}
                            </h5>
                            <button type="button" class="close" @click="CloseLimit">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>

                        <div class="modal-body">
                            <dynamic-form lang="en" ref="validatePlan" :buttons="buttons" :schema="FormSchema"
                                :mandatorytext="$t('MandatoryString')">
                                <template v-slot:tgslot-Limit="{ data }">


                                    <Field name="Limit" :rules="{ 'required': true }" v-slot="{ errors }">
                                        <div class="input-group">
                                            <input type="number" id="" v-model="data.fieldInfo.value" min="1"
                                                maxlength="365" v-bind:class="{ 'txtitems form-control ': true, }" />
                                        </div>
                                        <span v-if="errors[0]" name="Limit" class="invalid-feedback d-block">{{
                                            errors[0]
                                            }}</span>

                                    </Field>
                                </template>
                                <template v-slot:tgslot-DayLimit="{ data }">


                                    <Field name="DayLimit" :rules="{ 'required': true }" v-slot="{ errors }">
                                        <div class="input-group">
                                            <input type="number" id="" v-model="data.fieldInfo.value" min="1"
                                                maxlength="365" v-bind:class="{ 'txtitems form-control ': true, }" />

                                        </div>
                                        <span v-if="errors[0]" name="DayLimit" class="invalid-feedback d-block">{{
                                            errors[0]
                                            }}</span>

                                    </Field>
                                </template>
                            </dynamic-form>
                        </div>

                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import { placeholder } from '@mapbox/mapbox-gl-geocoder/lib/localization';
import DataService from '../../../services/DataService';
import {
    locateBillingService
} from "../../../services/locateBillingService";


export default {
    props: {
        callbackfunction: {
            type: Function,
            required: false
        },
        refCode: {
            type: String,
            required: false
        },
        EditLimitData: {
            type: Object,
            required: false
        },
        configurationId: {
            type: String,
            default: null
        },
        clientId:{
            type: Number,
            required: false
        },
        mode: {
            type: String,
            default: 'Edit'
        }
    },
    data() {

        return {
            isLoading: false,
            isEditLimit: true,
            id: 0,
            isVisibleUtility: true,
            clientsIds: '',
            type: "",
            FormSchema: [
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "SelectField",
                            label: this.$t('WorkCode'),
                            name: "WorkCode",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            config: {
                                options: [],
                            },
                            placeholder: this.$t('Select'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('AlternateWorkCode'),
                            name: "AlternateWorkcode",
                            value: "",
                            visibility: true,
                            config: {
                                options: [],
                            },
                            placeholder: this.$t('Select'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SlotField",
                            label: this.$t('LimitValue'),
                            name: "Limit",
                            value: "",
                            placeholder: '',
                            validationRules: { "required": false, max: 365 },
                            visibility: true,
                        }

                    ]
                },
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "SlotField",
                            label: this.$t('DayLimit'),
                            name: "DayLimit",
                            value: "",
                            placeholder: '',
                            validationRules: { "required": false, max: 365 },
                            visibility: true,
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('IsApplicableToAll'),
                            name: "ApplicableToAll",
                            visibility: true,
                            disabled: false,
                            value: "",
                            config: {
                                options: [{ value: "1", name: this.$t('Yes') }, { value: "0", name: this.$t('No') }],
                                onChange: this.onChangeApplicable
                            }

                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('UtilityName'),
                            name: "UtilityName",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                selectAll: true,
                                active: true,
                                inactive: true,
                                clear: true},
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": true
                            },
                        }
                        // {
                        //     astype: "SelectField",
                        //     label: this.$t('UtilityName'),
                        //     name: "UtilityName",
                        //     value: "",
                        //     visibility: true,
                        //     config: {
                        //         options: [],
                        //     },
                        //     placeholder: this.$t('Select'),
                        //     validationRules: { "required": true, max: 100 },
                        //     settings: {
                        //         isInSlot: true
                        //     }
                        // },
                    ]
                },

            ],
        }
    },
    computed: {
        buttons() {
            const baseButtons = [
                {
                    type: "submit",
                    class: "btn btn-success",
                    visibility: true,
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('SaveAndClose'),
                    onClick: this.SubmitData,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('Save'),
                    onClick: this.SubmitData
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.CloseLimit,
                },
            ];
            
            // Hide Save buttons when mode is View - filter out submit buttons
            if (this.mode === 'View') {
                return baseButtons.filter(btn => btn.type !== 'submit');
            }
            
            return baseButtons;
        }
    },
    created: async function () {
        var vm = this;
        await vm.GetDdlWorkCode();
        await vm.GetUtilityList();
    },
    mounted() {
        debugger
        if (this.EditLimitData && Object.keys(this.EditLimitData).length > 0 && this.refCode == 'Update') {
            this.BindEditDetail(this.EditLimitData);
        }
    },
    methods: {
        BindEditDetail: function(data) {
            var vm = this;
            vm.Id = data.limit_id;
            vm.configurationId != null ? vm.configurationId : 0;
            vm.$refs.validatePlan.updateProperty("WorkCode", "value", data.workCodeId);
            vm.$refs.validatePlan.updateProperty("AlternateWorkcode", "value", data.alternateWorkCodeId);
            vm.$refs.validatePlan.updateProperty("Limit", "value", data.limitValue);
            vm.$refs.validatePlan.updateProperty("DayLimit", "value", data.dayLimit);
            vm.$refs.validatePlan.updateProperty("ApplicableToAll", "value", data.isApplicableToAll);
            var isapplicable = vm.$refs.validatePlan.getPropertyValue("ApplicableToAll", "value", data.isApplicableToAll);
            if (isapplicable) {
                vm.$refs.validatePlan.updateProperty("UtilityName", "visibility", false);
                vm.$refs.validatePlan.updateProperty("UtilityName", "validationRules", false);
            }
            vm.$refs.validatePlan.updateProperty("UtilityName", "value", data.clientLimitId);
        },
        GetDdlWorkCode: async function () {
            var vm = this;
            vm.isLoading = true;
            await DataService.GetWorkCodeInfo().then((response) => {
                if (response.data != '' && response.data != null) {
                    var selctedValue = [];
                    if (response.data.length > 0) {
                        response.data.forEach((item, index) => {
                            selctedValue.push({
                                value: item.value,
                                name: item.name
                            })
                        })
                    }
                    vm.$refs.validatePlan.updateProperty("WorkCode", "config.options", selctedValue);
                    vm.$refs.validatePlan.updateProperty("AlternateWorkcode", "config.options", selctedValue);
                    vm.$refs.validatePlan.UpdateKeyValue();
                }
            });
            vm.isLoading = false;
        },
        GetUtilityList: async function () {
            // var vm = this;
            // var url = `clientId=${vm.clientId}&configId=${vm.configurationId != null ? vm.configurationId : 0}&reqFrom=LIMIT&clientsIds=''`;
            // await DataService.GetDdlUtility(url).then((response) => {
            //     if (response.data != null || response.data != '') {
            //         var selctedValue = [];
            //         if (response.data.length > 0) {
            //             response.data.forEach((item, index) => {
            //                 selctedValue.push({
            //                     value: item.UTILITY_ID,
            //                     name: item.UTILITY_NAME
            //                 })
            //             })
            //         }
            //         vm.$refs.validatePlan.updateProperty("UtilityName", "config.options", selctedValue);
            //         vm.$refs.validatePlan.UpdateKeyValue();
            //     }
            // });
            var vm = this;
            vm.isLoading = true;
            vm.selectedClientId = x;
            await vm.getBillingSetupId(x);
            var url = `clientId=${vm.clientId}&configId=${vm.configurationId != null ? vm.configurationId : 0}&reqFrom=LIMIT&clientIds=`;
            await locateBillingService.getUtilityList(url).then(response => {
                vm.isLoading = false;
                let SelectedUtilityList = [];
                debugger;
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                     vm.$refs.validateRuleConfig.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                     vm.$refs.validateRuleConfig.UpdateKeyValue();
                }
            }).catch(error => {
                vm.isLoading = false;
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        onChangeApplicable() {
            var utilityselectval = this.$refs.validatePlan.getPropertyValue("ApplicableToAll", "value");
            switch (utilityselectval) {
                case true:
                    this.$refs.validatePlan.updateProperty("UtilityName", "visibility", false);
                    this.$refs.validatePlan.updateProperty("UtilityName", "validationRules", false);
                    this.$refs.validatePlan.updateProperty("UtilityName", "value", "");
                    break;
                default:
                    this.$refs.validatePlan.updateProperty("UtilityName", "visibility", true);
                    this.$refs.validatePlan.updateProperty("UtilityName", "validationRules", true);
            }

        },
        SubmitData: async function (event) {
            var vm = this;
            vm.isLoading = true;
            const result = await vm.$refs.validatePlan.validateForm.validate();
            if (!result) {
                this.isLoading = false;
                return;
            }
            var chkutilityvalidation = vm.$refs.validatePlan.getPropertyValue("ApplicableToAll", "value");
            var selectedutility = vm.$refs.validatePlan.getPropertyValue("UtilityName", "value");
            if (result == true && chkutilityvalidation === false && selectedutility == "") {
                vm.$refs.validatePlan.updateProperty("UtilityName", "validationRules", true);
                vm.isLoading = false;
                return;
            }
            const id = this.Id >= 0 ? this.Id : 0;
            const ConfigId = vm.configurationId != null ? vm.configurationId : 0;
            const WorkCodeId = vm.$refs.validatePlan.getPropertyValue("WorkCode", "value");
            const AlternateWorkCodeId = vm.$refs.validatePlan.getPropertyValue("AlternateWorkcode", "value");
            const LimitValue = vm.$refs.validatePlan.getPropertyValue("Limit", "value");
            const DayLimit = vm.$refs.validatePlan.getPropertyValue("DayLimit", "value");
            const IsApplicableToAll = vm.$refs.validatePlan.getPropertyValue("ApplicableToAll", "value");
            const utilityname = vm.$refs.validatePlan.getPropertyValue("UtilityName", "value");
            var chkUtilityValue = utilityname;
            if (IsApplicableToAll == true) {
                chkUtilityValue = vm.$refs.validatePlan.updateProperty("UtilityName", "value", 0);
            }
            var obj = {
                limitId: id,
                client_id : vm.clientId,
                configuration_id: ConfigId,
                workcode_id: WorkCodeId,
                alternate_code: AlternateWorkCodeId,
                limit: LimitValue,
                limit_days: DayLimit,
                is_applicable_to_all: IsApplicableToAll,
                utility_id: chkUtilityValue != "" ? chkUtilityValue : vm.EditLimitData.clientLimitId,
                client_limit_name : chkUtilityValue,
                display_order: vm.EditLimitData.display_order != 0 ? vm.EditLimitData.displayOrder : 0
            }
            var jsondata = JSON.stringify(obj);
            var url = `Data=${jsondata}`;
            await DataService.CreateLimit(url).then((response) => {
                debugger
                if (response.data != '') {
                    debugger;
                    if (response.data[0].MSG == "INSERTED" && response.data[0].STATUS_CODE == 1) {
                        this.ShowAlert(this.$t('AddedSuccess', [this.$t('LimitValue')]), "Success", true, this.$t('Alert'));
                        if (textOnly != "Save") {
                            vm.CloseLimit();
                        }
                        vm.callbackfunction && vm.callbackfunction();
                        vm.ResetModel();

                    }
                    else if (response.data[0].MSG == "UPDATED" && response.data[0].STATUS_CODE == 2) {
                        this.ShowAlert(this.$t('UpdatedSuccess', [this.$t('LimitValue')]), "Success", true, this.$t('Alert'))
                        vm.callbackfunction && vm.callbackfunction();
                        vm.CloseLimit();

                    }
                    else {
                        vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));

                    }
                }
                vm.isLoading = false;
            });
        },
        ResetModel() {
            var vm = this;
            const id = 0;
            vm.$refs.validatePlan.updateProperty("WorkCode", "value", "");
            vm.$refs.validatePlan.updateProperty("AlternateWorkcode", "value", "");
            vm.$refs.validatePlan.updateProperty("Limit", "value", "");
            vm.$refs.validatePlan.updateProperty("DayLimit", "value", "");
            vm.$refs.validatePlan.updateProperty("ApplicableToAll", "value", "");
            vm.$refs.validatePlan.updateProperty("UtilityName", "value", "");
        },
        CloseLimit() {
            this.$emit('CloseLimit');
        },
    },
}
</script>

<style lang="scss" scoped></style>